class Solution {
public:
    bool isToeplitzMatrix(vector<vector<int>>& m) {
        int R=m.size(), C=m[0].size();
        for(int r=1;r<R;r++) for(int c=1;c<C;c++)
            if(m[r][c]!=m[r-1][c-1]) return false;
        return true;
    }
};

